type RelaxStream = { id: string; title: string; title_th: string; channel: string; youtube_url: string; embed_url: string; category: string; enabled: boolean };
type RelaxPreference = { streamId?: string; customYoutubeUrl?: string; volume: number; muted: boolean; minimized?: boolean };
const relaxStreams = (relaxStreamsConfig as RelaxStream[]).filter((stream) => stream.enabled && stream.embed_url && stream.youtube_url);

type Section = 'dashboard' | 'compare' | 'assistant' | 'portfolio' | 'calendar' | 'news';
function initialLanguage(): Language { const saved = localStorage.getItem(languageKey); return saved === 'en' || saved === 'th' ? saved : DEFAULT_LANGUAGE; }
function readPortfolio(): PortfolioHolding[] { try { return JSON.parse(localStorage.getItem(portfolioKey) ?? '[]'); } catch { return []; } }
function readSmartWatchlist(): string[] { try { const value = JSON.parse(localStorage.getItem(watchlistKey) ?? '[]'); return Array.isArray(value) ? value : []; } catch { return []; } }
function readRecentSearches(): AssetSearchItem[] { try { const value = JSON.parse(localStorage.getItem(recentSearchKey) ?? '[]'); return Array.isArray(value) ? value.slice(0, 8) : []; } catch { return []; } }
function readRelaxPreference(): RelaxPreference { try { const value = JSON.parse(localStorage.getItem(relaxPreferenceKey) ?? '{}') as Partial<RelaxPreference>; return { streamId: value.streamId, customYoutubeUrl: value.customYoutubeUrl, volume: typeof value.volume === 'number' ? value.volume : 35, muted: Boolean(value.muted), minimized: Boolean(value.minimized) }; } catch { return { volume: 35, muted: false, minimized: false }; } }

function assetTypeFor(assetType: string): Asset['type'] { return assetType === 'crypto' || assetType === 'etf' || assetType === 'index' || assetType === 'commodity' || assetType === 'fx' || assetType === 'macro' ? assetType : 'stock'; }
function categoryIdFor(asset: AssetSearchItem): string { return (asset.market || asset.exchange || asset.asset_type || 'Supported Universe').toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-|-$/g, '') || 'supported-universe'; }
function categoryNameFor(asset: AssetSearchItem): string { return asset.market || asset.exchange || asset.asset_type || 'Supported Universe'; }
function categoriesFromSectors(sectors: SectorItem[]): AssetCategory[] { const bySymbol = new Map<string, AssetSearchItem>(); sectors.flatMap((sector) => sector.assets).forEach((asset) => bySymbol.set(asset.symbol, asset)); const groups = new Map<string, AssetCategory>(); Array.from(bySymbol.values()).forEach((asset) => { const id = categoryIdFor(asset); const category = groups.get(id) ?? { id, name: categoryNameFor(asset), assets: [] }; category.assets.push({ symbol: asset.symbol, label: `${asset.symbol} | ${asset.label}`, type: assetTypeFor(asset.asset_type) }); groups.set(id, category); }); const preferred = ['us-stocks', 'thailand', 'crypto', 'etf', 'indices', 'commodities', 'forex', 'bonds', 'sector-etf', 'reit']; return Array.from(groups.values()).map((category) => ({ ...category, assets: category.assets.sort((a, b) => a.symbol.localeCompare(b.symbol)) })).sort((a, b) => { const ai = preferred.indexOf(a.id); const bi = preferred.indexOf(b.id); return (ai === -1 ? 99 : ai) - (bi === -1 ? 99 : bi) || a.name.localeCompare(b.name); }); }

