  const [portfolioEvaluation, setPortfolioEvaluation] = React.useState<PortfolioEvaluationResponse | null>(null);
  const [smartWatchlist, setSmartWatchlist] = React.useState<string[]>(readSmartWatchlist);
  const [watchlistQuotes, setWatchlistQuotes] = React.useState<AssetQuote[]>([]);
  const [compareInput, setCompareInput] = React.useState('');
  const [newHolding, setNewHolding] = React.useState<PortfolioHolding>({ symbol: 'BTC-USD', quantity: 0.1, averageCost: 50000, currency: 'USD' });
  const [initialCash, setInitialCash] = React.useState(100000);
  const [newTransaction, setNewTransaction] = React.useState<PortfolioTransaction>({ symbol: 'AAPL', side: 'buy', quantity: 1, price: 100, date: new Date().toISOString().slice(0, 10) });
  const [calendar, setCalendar] = React.useState<CalendarResponse | null>(null);
  const [news, setNews] = React.useState<NewsImpactResponse | null>(null);
  const [loading, setLoading] = React.useState(true);
  const [aboutOpen, setAboutOpen] = React.useState(false);
  const [relaxOpen, setRelaxOpen] = React.useState(false);
  const [relaxPreference, setRelaxPreference] = React.useState<RelaxPreference>(readRelaxPreference);

  React.useEffect(() => { localStorage.setItem(languageKey, language); }, [language]);
  React.useEffect(() => { localStorage.setItem(portfolioKey, JSON.stringify(portfolio)); }, [portfolio]);
  React.useEffect(() => { localStorage.setItem(watchlistKey, JSON.stringify(smartWatchlist)); }, [smartWatchlist]);
  React.useEffect(() => { localStorage.setItem(recentSearchKey, JSON.stringify(recentSearches)); }, [recentSearches]);
  React.useEffect(() => { localStorage.setItem(relaxPreferenceKey, JSON.stringify(relaxPreference)); }, [relaxPreference]);
  React.useEffect(() => { const timeout = window.setTimeout(() => setDebouncedAssetSearch(assetSearch.trim()), searchDebounceMs); return () => window.clearTimeout(timeout); }, [assetSearch]);
  React.useEffect(() => { api.watchlist().then((data) => { setCategories(data.categories); const first = data.categories[0]; if (first) { setCategoryId(first.id); setAssetSymbol(first.assets[0]?.symbol ?? 'BTC-USD'); } }).catch((error) => console.error('Failed to load watchlist', error)); api.sectors().then((data) => { setSectors(data.sectors); const generated = categoriesFromSectors(data.sectors); if (generated.length) { const first = generated[0]; setCategories(generated); setCategoryId(first.id); setSelectedSector(data.sectors.find((sector) => sector.assets.some((asset) => categoryIdFor(asset) === first.id))?.name ?? data.sectors[0]?.name ?? ''); setAssetSymbol((current) => generated.some((category) => category.assets.some((asset) => asset.symbol === current)) ? current : first.assets[0]?.symbol ?? current); } }).catch((error) => console.error('Failed to load sectors', error)); api.calendar().then(setCalendar).catch((error) => console.error('Failed to load calendar', error)); api.marketCondition().then(setMarketCondition).catch((error) => console.error('Failed to load market condition', error)); }, []);
  React.useEffect(() => { const query = debouncedAssetSearch; if (!query) { setSearchResults([]); setActiveSearchIndex(0); return; } let ok = true; api.searchAssets(query).then((payload) => { if (ok) { setSearchResults(payload.assets); setActiveSearchIndex(0); } }).catch((error) => console.error('Failed to search assets', error)); return () => { ok = false; }; }, [debouncedAssetSearch]);
  React.useEffect(() => { let ok = true; setLoading(true); Promise.allSettled([api.quote(assetSymbol), api.history(assetSymbol, range, range === '1d' ? '1h' : '1d'), api.technical(assetSymbol), api.analysis(assetSymbol), api.risk(assetSymbol), api.financials(assetSymbol), api.sentiment(assetSymbol), api.newsImpact(assetSymbol)]).then((results) => { if (!ok) return; const [q, h, tech, a, r, f, s, n] = results; if (q.status === 'fulfilled') setQuote(q.value); else console.error('Failed to load quote', q.reason); if (h.status === 'fulfilled') setHistory(h.value); else console.error('Failed to load history', h.reason); if (tech.status === 'fulfilled') setTechnical(tech.value); else console.error('Failed to load technical analysis', tech.reason); if (a.status === 'fulfilled') setAnalysis(a.value); else console.error('Failed to load analysis', a.reason); if (r.status === 'fulfilled') setRisk(r.value); else console.error('Failed to load risk', r.reason); if (f.status === 'fulfilled') setFinancials(f.value); else console.error('Failed to load financials', f.reason); if (s.status === 'fulfilled') setSentiment(s.value); else console.error('Failed to load sentiment', s.reason); if (n.status === 'fulfilled') setNews(n.value); else console.error('Failed to load news impact', n.reason); }).finally(() => ok && setLoading(false)); return () => { ok = false; }; }, [assetSymbol, range]);
