  const changeCategory = (id: string) => { const next = categories.find((category) => category.id === id); const nextSector = sectors.find((sector) => sector.assets.some((asset) => categoryIdFor(asset) === id)); setCategoryId(id); if (nextSector) setSelectedSector(nextSector.name); setAssetSymbol(next?.assets[0]?.symbol ?? assetSymbol); };
  const selectSearchAsset = (asset: AssetSearchItem) => { setCanonicalAsset(asset.symbol); setAssetSearch(''); setSearchResults([]); setRecentSearches((items) => [asset, ...items.filter((item) => item.symbol !== asset.symbol)].slice(0, 8)); };
