  const moveWatchlist = (symbol: string, direction: -1 | 1) => setSmartWatchlist((items) => { const index = items.indexOf(symbol); const nextIndex = index + direction; if (index < 0 || nextIndex < 0 || nextIndex >= items.length) return items; const next = [...items]; [next[index], next[nextIndex]] = [next[nextIndex], next[index]]; return next; });
  const toggleIndicator = (indicator: string) => setActiveIndicators((items) => items.includes(indicator) ? items.filter((item) => item !== indicator) : [...items, indicator]);
  const chooseSectorAsset = (symbol: string) => { setCanonicalAsset(symbol); setCompareSymbols((items) => items.includes(symbol) ? items : [...items.slice(0, 4), symbol]); };
  const addCompareSymbol = (symbol: string) => setCompareSymbols((items) => { const normalized = symbol.trim().toUpperCase(); if (!normalized || items.includes(normalized) || items.length >= 5) return items; return [...items, normalized]; });
  const removeCompareSymbol = (symbol: string) => setCompareSymbols((items) => items.length <= 2 ? items : items.filter((item) => item !== symbol));
  const submitCompareInput = () => { addCompareSymbol(compareInput); setCompareInput(''); };
  const handleSearchKeyDown = (event: React.KeyboardEvent<HTMLInputElement>) => { if (!searchResults.length) return; if (event.key === 'ArrowDown') { event.preventDefault(); setActiveSearchIndex((index) => Math.min(index + 1, searchResults.length - 1)); } if (event.key === 'ArrowUp') { event.preventDefault(); setActiveSearchIndex((index) => Math.max(index - 1, 0)); } if (event.key === 'Enter') { event.preventDefault(); selectSearchAsset(searchResults[activeSearchIndex]); } if (event.key === 'Escape') { setSearchResults([]); } };
