function RelaxMusicPanel({ labels: l, language, open, streams, preference, setPreference, onClose }: { labels: typeof labels.th; language: Language; open: boolean; streams: RelaxStream[]; preference: RelaxPreference; setPreference: React.Dispatch<React.SetStateAction<RelaxPreference>>; onClose: () => void }) { const iframeRef = React.useRef<HTMLIFrameElement>(null); const [hasStarted, setHasStarted] = React.useState(false); const [playing, setPlaying] = React.useState(false); const [draftUrl, setDraftUrl] = React.useState(preference.customYoutubeUrl ?? ''); const selected = streams.find((stream) => stream.id === preference.streamId) ?? streams[0]; const customEmbed = youtubeUrlToEmbed(preference.customYoutubeUrl ?? ''); const active = customEmbed ? { title: 'Custom YouTube', title_th: 'YouTube ที่กำหนดเอง', channel: 'YouTube', category: 'custom', youtube_url: preference.customYoutubeUrl ?? '', embed_url: customEmbed } : selected; const title = active ? (language === 'th' ? active.title_th : active.title) : l.streamUnavailable; const sendCommand = (func: string, args: unknown[] = []) => iframeRef.current?.contentWindow?.postMessage(JSON.stringify({ event: 'command', func, args }), youtubePostMessageOrigin(active?.embed_url)); const updateVolume = (volume: number) => { setPreference((value) => ({ ...value, volume })); sendCommand('setVolume', [volume]); }; const toggleMute = () => { const muted = !preference.muted; setPreference((value) => ({ ...value, muted })); sendCommand(muted ? 'mute' : 'unMute'); }; const saveCustomUrl = () => { setHasStarted(false); setPlaying(false); setPreference((value) => ({ ...value, customYoutubeUrl: draftUrl.trim() || undefined })); }; const clearCustomUrl = () => { setDraftUrl(''); setHasStarted(false); setPlaying(false); setPreference((value) => ({ ...value, customYoutubeUrl: undefined })); }; const play = () => { if (!active) return; setHasStarted(true); setPlaying(true); window.setTimeout(() => { sendCommand(preference.muted ? 'mute' : 'unMute'); sendCommand('setVolume', [preference.volume]); sendCommand('playVideo'); }, 400); }; const pause = () => { setPlaying(false); sendCommand('pauseVideo'); }; const minimized = Boolean(preference.minimized); const minimize = () => setPreference((value) => ({ ...value, minimized: true })); const expand = () => setPreference((value) => ({ ...value, minimized: false })); const close = () => { pause(); onClose(); }; React.useEffect(() => { if (!hasStarted) return; sendCommand(preference.muted ? 'mute' : 'unMute'); sendCommand('setVolume', [preference.volume]); }, [preference.muted, preference.volume, hasStarted]); if (!open) return null; if (minimized) return <aside className="relax-panel relax-panel-minimized" aria-label={l.relaxMode}><div className="flex items-center justify-between gap-3"><div className="min-w-0"><p className="truncate text-xs font-semibold text-white">{title}</p>{active && <p className="truncate text-xs text-terminal-muted">{active.channel}</p>}</div><div className="flex shrink-0 gap-2"><button className="icon-button" onClick={playing ? pause : play} aria-label={playing ? l.pause : l.play}>{playing ? <Pause size={15} /> : <Play size={15} />}</button><button className="icon-button" onClick={toggleMute} aria-label={preference.muted ? l.unmute : l.mute}>{preference.muted ? <VolumeX size={15} /> : <Volume2 size={15} />}</button><button className="watch-button px-3" onClick={expand} aria-label={language === 'th' ? 'ขยาย' : 'Expand'}>{language === 'th' ? 'ขยาย' : 'Expand'}</button><button className="icon-button" onClick={close} aria-label={l.close}><X size={15} /></button></div></div>{hasStarted && active ? <iframe className="relax-hidden-frame" ref={iframeRef} title={title} src={youtubeEmbedSrc(active.embed_url, playing)} allow="autoplay; encrypted-media; picture-in-picture" allowFullScreen /> : null}</aside>; return <aside className="relax-panel" aria-label={l.relaxMode}><div className="mb-3 flex items-start justify-between gap-3"><div><p className="text-xs font-semibold uppercase tracking-[0.16em] text-terminal-cyan">{l.relaxMode}</p><h2 className="mt-1 text-sm font-semibold text-white">{title}</h2>{active && <p className="mt-1 text-xs text-terminal-muted">{active.channel} | {active.category}</p>}</div><div className="flex gap-2"><button className="watch-button px-3" onClick={minimize} aria-label={language === 'th' ? 'ย่อ' : 'Minimize'}>{language === 'th' ? 'ย่อ' : 'Minimize'}</button><button className="icon-button" onClick={close} aria-label={l.close}><X size={16} /></button></div></div>{active ? <><label className="field-label">{l.source}</label><div className="select-shell mb-3"><select value={selected?.id ?? ''} onChange={(event) => { setHasStarted(false); setPlaying(false); clearCustomUrl(); setPreference((value) => ({ ...value, streamId: event.target.value })); }}>{streams.map((stream) => <option key={stream.id} value={stream.id}>{language === 'th' ? stream.title_th : stream.title}</option>)}</select><ChevronDown size={16} /></div><div className="mb-3 grid gap-2 sm:grid-cols-[1fr_auto_auto]"><input className="input-shell" value={draftUrl} onChange={(event) => setDraftUrl(event.target.value)} placeholder="Paste YouTube URL" aria-label="Paste YouTube URL" /><button className="about-button" onClick={saveCustomUrl}>{l.add}</button><button className="about-button" onClick={clearCustomUrl}>{l.remove}</button></div>{preference.customYoutubeUrl && !customEmbed && <p className="mb-3 rounded-md border border-terminal-amber/40 bg-terminal-panel2 p-2 text-xs text-terminal-amber">Embed is unavailable for this URL. Please use a standard YouTube watch or embed URL.</p>}<div className="relax-frame">{hasStarted ? <iframe ref={iframeRef} title={title} src={youtubeEmbedSrc(active.embed_url, playing)} allow="autoplay; encrypted-media; picture-in-picture" allowFullScreen /> : <div className="relax-idle"><Music2 size={28} /><p>{l.optionalWellbeing}</p></div>}</div><div className="mt-3 grid gap-2 sm:grid-cols-[auto_auto_1fr_auto]"><button className="about-button" onClick={playing ? pause : play}>{playing ? <Pause size={16} /> : <Play size={16} />}{playing ? l.pause : l.play}</button><button className="about-button" onClick={toggleMute}>{preference.muted ? <VolumeX size={16} /> : <Volume2 size={16} />}{preference.muted ? l.unmute : l.mute}</button><label className="flex items-center gap-2 text-xs text-terminal-muted"><span>{l.volume}</span><input className="w-full" type="range" min="0" max="100" value={preference.volume} onChange={(event) => updateVolume(Number(event.target.value))} /></label><a className="about-button" href={active.youtube_url} target="_blank" rel="noreferrer"><ExternalLink size={16} />{l.openYoutube}</a></div><p className="mt-3 text-xs leading-5 text-terminal-muted">{l.optionalWellbeing}. {l.youtubePolicy}</p></> : <EmptyState message={l.streamUnavailable} />}</aside>; }
function youtubeUrlToEmbed(url: string): string { try { const parsed = new URL(url); const host = parsed.hostname.toLowerCase(); const isShort = host === 'youtu.be'; const isWatch = ['youtube.com', 'www.youtube.com', 'm.youtube.com'].includes(host); const isEmbed = ['www.youtube.com', 'youtube.com', 'www.youtube-nocookie.com', 'youtube-nocookie.com'].includes(host) && parsed.pathname.startsWith('/embed/'); const rawVideoId = isShort ? parsed.pathname.replace('/', '') : isEmbed ? parsed.pathname.split('/embed/')[1]?.split('/')[0] : isWatch ? parsed.searchParams.get('v') : ''; const videoId = sanitizeYouTubeId(rawVideoId ?? ''); const listId = sanitizeYouTubeListId(parsed.searchParams.get('list') ?? ''); return videoId ? `https://www.youtube.com/embed/${videoId}${listId ? `?list=${listId}` : ''}` : ''; } catch { return ''; } }
function sanitizeYouTubeId(value: string): string { return /^[A-Za-z0-9_-]{6,32}$/.test(value) ? value : ''; }
function sanitizeYouTubeListId(value: string): string { return /^[A-Za-z0-9_-]{6,80}$/.test(value) ? value : ''; }
function youtubePostMessageOrigin(embedUrl: string | undefined): string { try { return embedUrl ? new URL(embedUrl).origin : 'https://www.youtube.com'; } catch { return 'https://www.youtube.com'; } }
function youtubeEmbedSrc(embedUrl: string, autoplay: boolean): string {
  const origin = typeof window !== 'undefined' ? window.location.origin : '';
  const separator = embedUrl.includes('?') ? '&' : '?';
  return (
    embedUrl +
    separator +
    'enablejsapi=1&playsinline=1&rel=0&autoplay=' +
    (autoplay ? '1' : '0') +
    '&origin=' +
    encodeURIComponent(origin)
  );
}
